import type { ExtractTraits, TraitOrRelation } from '../../trait/types';
import { universe } from '../../universe/universe';
import { createModifier } from '../modifier';
import type { Modifier, PredicateModifier } from '../types';
import { createTrackingId, setTrackingMasks } from '../utils/tracking-cursor';

export function createAdded() {
    const id = createTrackingId();

    for (const world of universe.worlds) {
        if (!world) continue;
        setTrackingMasks(world, id);
    }

    function Added<T extends TraitOrRelation[]>(...inputs: T): Modifier<ExtractTraits<T>, `added-${number}`>;
    function Added(predicate: PredicateModifier): Modifier<[], `added-${number}`>;
    function Added(...inputs: (TraitOrRelation | PredicateModifier)[]): Modifier<any, `added-${number}`> {
        const predicate = inputs.length === 1 && (inputs[0] as PredicateModifier).type === 'predicate'
            ? inputs[0] as PredicateModifier : undefined;
        if (predicate) {
            const modifier = createModifier(`added-${id}`, id, []) as Modifier<any, `added-${number}`>;
            modifier.predicate = predicate as any;
            return modifier;
        }
        const traits = (inputs as TraitOrRelation[]).map((input) =>
            isRelation(input) ? input[$internal].trait : input
        ) as ExtractTraits<T>;
        return createModifier(`added-${id}`, id, traits as any);
    }
    return Added;
}

